from decimal import Decimal, InvalidOperation, ROUND_HALF_UP

def parse_monto(raw):
    try:
        d = Decimal(str(raw).strip().replace(',', '.'))
    except (InvalidOperation, ValueError):
        raise ValueError('monto no numérico')
    if not d.is_finite():
        raise ValueError('monto no finito')
    if d < 0:
        raise ValueError('monto negativo')
    return d.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)

for v in ["10.5", "3,25", "abc", "-1"]:
    try:
        print(v, parse_monto(v))
    except ValueError as e:
        print(v, e)

class DataLoadError(Exception):
    pass

def load_text(path_fn):
    try:
        return path_fn()
    except OSError as e:
        raise DataLoadError('load failed') from e

def bad_reader():
    raise OSError('no file')

try:
    load_text(bad_reader)
except DataLoadError as e:
    print(type(e).__name__, e.__cause__.__class__.__name__)

state = {"closed": False}

def work(fail: bool):
    try:
        if fail:
            raise RuntimeError("boom")
        return "ok"
    finally:
        state["closed"] = True

for f in [False, True]:
    state["closed"] = False
    try:
        print(work(f), "closed", state["closed"])
    except RuntimeError:
        print("err", "closed", state["closed"])

def good_handler(fn):
    try:
        return ("ok", fn())
    except ValueError as e:
        return ("quarantine", str(e))

def boom():
    raise ValueError("bad row")

def fatal():
    raise RuntimeError("config")

print(good_handler(lambda: 1))
print(good_handler(boom))
try:
    good_handler(fatal)
except RuntimeError as e:
    print("propagated", e)

